// usage: ./lazy_bench <binary-file> [target-records]
//   binary-file    raw Avro binary stream (e.g. registration.bin)
//   target-records approximate total records per timed pass (default: 1 000 000)

#include <chrono>
#include <cstdint>
#include <cstdlib>
#include <fstream>
#include <iomanip>
#include <iostream>
#include <vector>

#include CHISEL_HEADER
#include CHISEL_LAZY_FILTER

using Root = CHISEL_ROOT;

int main(int argc, char* argv[]) {
    if (argc < 2) {
        std::cerr << "usage: " << argv[0] << " <binary-file> [target-records]\n";
        return 1;
    }

    const long target_recs = (argc >= 3) ? std::atol(argv[2]) : 1000000L;

    // Load the seed binary (a small number of records)
    std::ifstream f(argv[1], std::ios::binary);
    if (!f) {
        std::cerr << "cannot open: " << argv[1] << '\n';
        return 1;
    }

    const std::vector<uint8_t> seed(std::istreambuf_iterator<char>(f),
                                    std::istreambuf_iterator<char>{});
    f.close();

    // Count records in the seed buffer
    std::size_t n_seed = 0;
    {
        chisel::span<const uint8_t> s{seed.data(), seed.size()};
        std::size_t pos = 0;
        while (pos < s.size()) { Root::decode(s, pos); ++n_seed; }
    }
    if (n_seed == 0) { std::cerr << "no records in input\n"; return 1; }

    // Build a large buffer by tiling the seed to reach target_recs
    const std::size_t repeats =
        static_cast<std::size_t>((target_recs + static_cast<long>(n_seed) - 1)
                                  / static_cast<long>(n_seed));
    std::vector<uint8_t> buf;
    buf.reserve(seed.size() * repeats);
    for (std::size_t i = 0; i < repeats; ++i)
        buf.insert(buf.end(), seed.begin(), seed.end());

    const std::size_t total_recs = n_seed * repeats;
    const chisel::span<const uint8_t> span{buf.data(), buf.size()};
    std::cerr << "buffer: " << buf.size() << " bytes, " << total_recs << " records\n";

    auto run_pass = [&]() -> std::size_t {
        std::size_t matched = 0;
        std::size_t pos = 0;
        while (pos < span.size()) {
            auto r = Root::reader(span, pos);
            bool match = false;
            chisel_test_filter(r, match);
            if (match) ++matched;
        }
        return matched;
    };

    // Warm-up pass (not timed)
    std::cerr << "(warm-up) matched: " << run_pass() << '\n';

    // Timed passes
    constexpr int N_RUNS = 5;
    std::cout << std::fixed << std::setprecision(2);
    for (int run = 0; run < N_RUNS; ++run) {
        const auto t0 = std::chrono::steady_clock::now();
        const std::size_t matched = run_pass();
        const auto t1 = std::chrono::steady_clock::now();

        const double ns = std::chrono::duration<double, std::nano>(t1 - t0).count();
        const double ns_per_rec = ns / static_cast<double>(total_recs);
        const double mrecs_per_sec = static_cast<double>(total_recs) / (ns * 1e-9) / 1e6;

        std::cout << "run " << run + 1 << ": "
                  << static_cast<int64_t>(ns_per_rec) << " ns/rec  "
                  << mrecs_per_sec << " Mrec/s"
                  << "  (matched=" << matched << ")\n";
    }

    return 0;
}
